#!/usr/bin/env python3
"""One-time Mobile Edge materialization for SmartResponsor Mobiling."""
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
FILES = {
    'mobile-edge/package.json': '{\n  "name": "mobile-edge",\n  "private": true,\n  "type": "module",\n  "scripts": {\n    "dev": "tsx src/app.ts",\n    "build": "tsc -p tsconfig.json",\n    "typecheck": "tsc -p tsconfig.json --noEmit",\n    "start": "node dist/app.js"\n  },\n  "dependencies": {\n    "@aws-sdk/client-s3": "^3.600.0",\n    "@fastify/cors": "^9.0.1",\n    "@fastify/helmet": "^12.2.0",\n    "@fastify/rate-limit": "^8.0.0",\n    "@fastify/static": "^7.0.4",\n    "better-sqlite3": "^11.3.0",\n    "fastify": "^4.28.1",\n    "fastify-raw-body": "^4.3.0",\n    "jose": "^5.9.6",\n    "pg": "^8.13.0",\n    "pino": "^9.4.0",\n    "prom-client": "^15.1.3"\n  },\n  "devDependencies": {\n    "@types/better-sqlite3": "^7.6.11",\n    "@types/node": "^22.7.4",\n    "@types/pg": "^8.11.10",\n    "tsx": "^4.19.1",\n    "typescript": "^5.6.3"\n  }\n}\n',
    'mobile-edge/src/env.ts': 'const integer = (name: string, fallback: number): number =>\n  Number.parseInt(process.env[name] || String(fallback), 10);\n\nconst boolean = (name: string, fallback: boolean): boolean =>\n  (process.env[name] || String(fallback)).toLowerCase() === "true";\n\nconst list = (name: string, fallback = ""): string[] =>\n  (process.env[name] || fallback).split(",").map((value) => value.trim()).filter(Boolean);\n\nexport const ENV = {\n  NODE_ENV: process.env.NODE_ENV || "development",\n  PORT: integer("PORT", 8080),\n  ADMIN_TOKEN: process.env.ADMIN_TOKEN || "dev",\n  ADMIN_ALLOW_IPS: list("ADMIN_ALLOW_IPS"),\n  CSRF_REQUIRED: boolean("CSRF_REQUIRED", false),\n  JWT_SECRET: process.env.JWT_SECRET || "devsecret",\n  JWT_PREV_SECRET: process.env.JWT_PREV_SECRET || "",\n  JWT_PREV_EXP_TS: integer("JWT_PREV_EXP_TS", 0),\n  JWT_TTL_SEC: integer("JWT_TTL_SEC", 3600),\n  DEV_BEARER: process.env.DEV_BEARER || "Bearer dev",\n  METRICS_ENABLED: boolean("METRICS_ENABLED", false),\n  ALLOW_ORIGINS: list("ALLOW_ORIGINS", "*"),\n  TRACE_RESPONSE_HEADER: process.env.TRACE_RESPONSE_HEADER || "Trace-Id",\n  ZIPKIN_URL: process.env.ZIPKIN_URL || "",\n  LOG_SHIP_URL: process.env.LOG_SHIP_URL || "",\n  CONFIG_VERSION: process.env.CONFIG_VERSION || "1",\n  CONFIG_SECRET_V1: process.env.CONFIG_SECRET_V1 || "changeme",\n  CONFIG_ED25519_PRIVATE: process.env.CONFIG_ED25519_PRIVATE || "",\n  CONFIG_KEY_ID: process.env.CONFIG_KEY_ID || "k1",\n  ANALYTIC_SECRET: process.env.ANALYTIC_SECRET || "dev-analytic",\n  RATE_MOBILE_RPM: integer("RATE_MOBILE_RPM", 120),\n  CORE_COMMERCE_URL: process.env.CORE_COMMERCE_URL || "http://localhost:9000",\n  CORE_AUTH: process.env.CORE_AUTH || "",\n  CORE_TIMEOUT_MS: integer("CORE_TIMEOUT_MS", 3000),\n  CB_FAILS_OPEN: integer("CB_FAILS_OPEN", 5),\n  CB_COOLDOWN_MS: integer("CB_COOLDOWN_MS", 20000),\n  STORE: (process.env.STORE || "sqlite").toLowerCase(),\n  DB_PATH: process.env.DB_PATH || "data/mobile-edge.sqlite",\n  DB_URL: process.env.DB_URL || "postgres://postgres:postgres@localhost:5432/mobile_edge",\n  WEBHOOK_URL_REQUEUE: process.env.WEBHOOK_URL_REQUEUE || "",\n  WEBHOOK_URL_PURGE: process.env.WEBHOOK_URL_PURGE || "",\n  WEBHOOK_SECRET: process.env.WEBHOOK_SECRET || "dev-webhook",\n  S3_BUCKET: process.env.S3_BUCKET || "",\n  S3_REGION: process.env.S3_REGION || "",\n  REQUEUE_ENABLED: boolean("REQUEUE_ENABLED", false),\n  REQUEUE_BASE_MS: integer("REQUEUE_BASE_MS", 1000),\n  REQUEUE_CAP_MS: integer("REQUEUE_CAP_MS", 600000),\n  REQUEUE_RPM: integer("REQUEUE_RPM", 60),\n  REQUEUE_DAILY: integer("REQUEUE_DAILY", 10000),\n  REQUEUE_CONCURRENCY: integer("REQUEUE_CONCURRENCY", 4),\n  DLQ_TTL_DAYS: integer("DLQ_TTL_DAYS", 30),\n};\n\nexport function assertRuntimeEnv(): void {\n  if (ENV.NODE_ENV !== "production") return;\n  const invalid = [\n    ["ADMIN_TOKEN", ENV.ADMIN_TOKEN, "dev"],\n    ["JWT_SECRET", ENV.JWT_SECRET, "devsecret"],\n    ["CONFIG_SECRET_V1", ENV.CONFIG_SECRET_V1, "changeme"],\n    ["ANALYTIC_SECRET", ENV.ANALYTIC_SECRET, "dev-analytic"],\n  ].filter(([, value, forbidden]) => value === forbidden).map(([name]) => name);\n  if (invalid.length > 0) {\n    throw new Error(`Unsafe production configuration: ${invalid.join(", ")}`);\n  }\n}\n',
    'mobile-edge/src/metrics.ts': 'import type { FastifyInstance } from "fastify";\nimport { ENV } from "./env.js";\n\nlet client: any;\nlet register: any;\nlet requestCounter: any;\nlet durationHistogram: any;\nlet circuitCounter: any;\nlet eventCounter: any;\n\nasync function ensure(): Promise<boolean> {\n  if (!ENV.METRICS_ENABLED) return false;\n  if (!client) {\n    client = await import("prom-client");\n    register = client.register;\n    client.collectDefaultMetrics();\n    requestCounter = new client.Counter({ name: "http_requests_total", help: "HTTP request count", labelNames: ["route", "code"] });\n    durationHistogram = new client.Histogram({ name: "http_duration_ms", help: "HTTP handler duration", buckets: [25, 50, 100, 250, 500, 1000, 2000] });\n    circuitCounter = new client.Counter({ name: "circuit_state_total", help: "Circuit state transitions", labelNames: ["state"] });\n    eventCounter = new client.Counter({ name: "mobile_edge_event_total", help: "Mobile edge event count", labelNames: ["name", "label"] });\n  }\n  return true;\n}\n\nexport const M = {\n  async route(app: FastifyInstance): Promise<void> {\n    if (!(await ensure())) return;\n    app.get("/metrics", async (_request, reply) => {\n      reply.header("Content-Type", register.contentType);\n      return register.metrics();\n    });\n  },\n  async observe(route: string, code: number, durationMs: number): Promise<void> {\n    if (!(await ensure())) return;\n    requestCounter.inc({ route, code: String(code) });\n    durationHistogram.observe(durationMs);\n  },\n  async circuit(state: "open" | "half_open" | "closed"): Promise<void> {\n    if (!(await ensure())) return;\n    circuitCounter.inc({ state });\n  },\n  async inc(name: string, label: Record<string, unknown> = {}): Promise<void> {\n    if (!(await ensure())) return;\n    const serialized = Object.entries(label).sort(([left], [right]) => left.localeCompare(right)).map(([key, value]) => `${key}=${String(value)}`).join(",");\n    eventCounter.inc({ name, label: serialized });\n  },\n};\n',
    'mobile-edge/src/app.ts': 'import Fastify from "fastify";\nimport cors from "@fastify/cors";\nimport helmet from "@fastify/helmet";\nimport rateLimit from "@fastify/rate-limit";\nimport rawBody from "fastify-raw-body";\nimport { assertRuntimeEnv, ENV } from "./env.js";\nimport { traceMw } from "./middleware/trace.js";\nimport { M } from "./metrics.js";\nimport routeAdmin from "./routes/admin.js";\nimport routeApiKey from "./routes/apikey.js";\nimport routeAnalytic from "./routes/analytic.js";\nimport routeBackup from "./routes/backup.js";\nimport routeConfig from "./routes/config.js";\nimport routeCore from "./routes/core.js";\nimport routeEntitlement from "./routes/entitlement.js";\nimport routeFlag from "./routes/flag.js";\nimport routeHealth from "./routes/health.js";\nimport routeMetrics from "./routes/metrics.js";\nimport routePush from "./routes/push.js";\nimport routeReceipt from "./routes/receipt.js";\nimport routeSecret from "./routes/secret.js";\nimport routeSession from "./routes/session.js";\nimport routeSync from "./routes/sync.js";\nimport routeWebhook from "./routes/webhook.js";\nimport { startRequeue } from "./worker/requeue.js";\n\nassertRuntimeEnv();\n\nconst app = Fastify({ logger: true });\nawait app.register(helmet, { contentSecurityPolicy: false });\nawait app.register(cors, {\n  origin(origin, callback) {\n    const allowed = ENV.ALLOW_ORIGINS.includes("*") || !origin || ENV.ALLOW_ORIGINS.includes(origin);\n    callback(null, allowed);\n  },\n});\nawait app.register(rateLimit, {\n  global: false,\n  max: ENV.RATE_MOBILE_RPM,\n  timeWindow: "1 minute",\n  keyGenerator: (request) => String(request.headers["x-api-key"] || request.ip),\n});\nawait app.register(rawBody, { field: "rawBody", global: false, encoding: false, runFirst: true });\n\napp.addHook("onRequest", async (request, reply) => {\n  (request as any).startedAt = Date.now();\n  await traceMw(request, reply);\n});\napp.addHook("onSend", async (request, reply, payload) => {\n  const duration = Date.now() - Number((request as any).startedAt || Date.now());\n  await M.observe(String((request as any).routerPath || request.routeOptions?.url || request.url), reply.statusCode || 200, duration);\n  return payload;\n});\napp.setErrorHandler((error: any, _request, reply) => {\n  const status = Number(error.statusCode || 500);\n  reply.status(status).send({ error: status >= 500 ? "internal_error" : error.message });\n});\n\nawait routeHealth(app);\nawait routeSession(app);\nawait routeFlag(app);\nawait routeConfig(app);\nawait routeEntitlement(app);\nawait routePush(app);\nawait routeReceipt(app);\nawait routeAnalytic(app);\nawait routeSync(app);\nawait routeCore(app);\nawait routeApiKey(app);\nawait routeAdmin(app);\nawait routeBackup(app);\nawait routeWebhook(app);\nawait routeSecret(app);\nawait routeMetrics(app);\n\nstartRequeue();\n\ntry {\n  await app.listen({ port: ENV.PORT, host: "0.0.0.0" });\n  app.log.info({ port: ENV.PORT }, "mobile-edge listening");\n} catch (error) {\n  app.log.error(error);\n  process.exit(1);\n}\n',
    'mobile-edge/src/routes/admin.ts': 'import { FastifyInstance } from "fastify";\nimport { adminGuard } from "../middleware/admin.js";\nimport { getStore } from "../repository/index.js";\nimport { toNdjson } from "../util/ndjson.js";\nimport { putToS3 } from "../util/s3.js";\nimport { hookRequeue } from "../webhook.js";\nimport { M } from "../metrics.js";\n\nexport default async function route(app: FastifyInstance): Promise<void> {\n  app.get("/admin/dlq/receipt", async (request: any) => { adminGuard(request); const store = await getStore(); const query = request.query || {}; return store.dlqSearch("receipt", { afterId: Number(query.afterId || 0), limit: Math.min(1000, Number(query.limit || 100)), apiKey: query.apiKey ? String(query.apiKey) : undefined, reason: query.reason ? String(query.reason) : undefined, statusMin: query.statusMin != null ? Number(query.statusMin) : undefined, statusMax: query.statusMax != null ? Number(query.statusMax) : undefined, q: query.q ? String(query.q) : undefined }); });\n  app.delete("/admin/dlq/receipt/:id", async (request: any, reply) => { adminGuard(request); await (await getStore()).dlqDelete(Number(request.params.id)); return reply.status(204).send(); });\n  app.post("/admin/dlq/receipt/requeue/:id", async (request: any, reply) => { adminGuard(request); const store = await getStore(); const item = await store.dlqGet(Number(request.params.id)); if (!item) return reply.status(404).send({ error: "not_found" }); const { verifyReceiptViaCore } = await import("../adapter/http/commerce.js"); const output = await verifyReceiptViaCore(item.payload); if (output.status >= 400) { await store.dlqUpdateAttempt(item.id, item.attempts + 1, Date.now() + 60_000); await M.inc("dlqRequeue", { mode: "manual", result: "fail" }); await hookRequeue({ mode: "manual", id: item.id, reason: item.reason, apiKey: item.apiKey || null, attempts: item.attempts + 1, status: output.status }); return reply.send({ requeued: false, status: output.status, body: output.body }); } await store.dlqDelete(item.id); await M.inc("dlqRequeue", { mode: "manual", result: "success" }); await hookRequeue({ mode: "manual", id: item.id, reason: item.reason, apiKey: item.apiKey || null, attempts: item.attempts, status: output.status }); return reply.send({ requeued: true, status: output.status, body: output.body }); });\n  app.get("/admin/dlq/receipt/export", async (request: any, reply) => { adminGuard(request); const format = String(request.query?.format || "ndjson"); const limit = Math.min(100000, Number(request.query?.limit || 10000)); const rows = await (await getStore()).dlqSearch("receipt", { limit }); if (format === "json") return reply.type("application/json").send(rows); reply.header("Content-Disposition", "attachment; filename=dlq-receipt.ndjson"); return reply.type("application/x-ndjson").send(toNdjson(rows)); });\n  app.post("/admin/dlq/receipt/export/s3", async (request: any) => { adminGuard(request); const limit = Math.min(100000, Number(request.body?.limit || 10000)); const rows = await (await getStore()).dlqSearch("receipt", { limit }); const timestamp = new Date().toISOString().replace(/[:.]/g, "-"); const key = `dlq/receipt-${timestamp}.ndjson`; return { ok: true, s3: await putToS3(key, toNdjson(rows), "application/x-ndjson") }; });\n}\n',
    'mobile-edge/src/routes/core.ts': 'import { FastifyInstance } from "fastify";\nimport { coreCall } from "../adapter/http/core.js";\nimport { adminGuard } from "../middleware/admin.js";\nimport * as circuit from "../service/circuit.js";\n\nexport default async function route(app: FastifyInstance): Promise<void> {\n  app.post("/mobile/core/test", async (request: any) => coreCall("/test", request.body || {}));\n  app.get("/admin/circuit", async (request: any) => {\n    adminGuard(request);\n    return circuit.status();\n  });\n}\n',
    'mobile-edge/src/routes/webhook.ts': 'import { FastifyInstance } from "fastify";\nimport { adminGuard } from "../middleware/admin.js";\nimport { getStore } from "../repository/index.js";\n\nexport default async function route(app: FastifyInstance): Promise<void> {\n  app.get("/admin/webhook/subscription", async (request: any) => { adminGuard(request); return (await getStore()).whList(); });\n  app.post("/admin/webhook/subscription", async (request: any, reply) => { adminGuard(request); const { id, url, secret, enabled = true, events = [], retry_max = 12, backoff_base_ms = 1000, backoff_cap_ms = 600000 } = request.body || {}; if (!id || !url || !secret || !Array.isArray(events) || events.length === 0) return reply.status(400).send({ error: "bad_request" }); await (await getStore()).whUpsert({ id: String(id), url: String(url), secret: String(secret), enabled: Boolean(enabled), events: events.map(String), retry_max: Number(retry_max), backoff_base_ms: Number(backoff_base_ms), backoff_cap_ms: Number(backoff_cap_ms) }); return { ok: true }; });\n  app.get("/admin/webhook/delivery", async (request: any) => { adminGuard(request); const query = request.query || {}; return (await getStore()).whSearch(query.event, query.status, query.sinceTs ? Number(query.sinceTs) : undefined, Math.min(1000, Number(query.limit || 200))); });\n  app.post("/admin/webhook/delivery/replay/:id", async (request: any, reply) => { adminGuard(request); const store = await getStore(); const delivery = await store.whGet(Number(request.params.id)); if (!delivery) return reply.status(404).send({ error: "not_found" }); await store.whUpdateAttempt(delivery.id, delivery.attempts, 0, delivery.lastStatus ?? null, delivery.durationMs ?? null); return { ok: true, id: delivery.id }; });\n}\n',
}

for relative, content in FILES.items():
    path = ROOT / relative
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")
print(f"Materialized {len(FILES)} Mobile Edge files")
